   }
-  _Tp __2r(_Tp(2) * __x.real());
-  _Tp __2i(_Tp(2) * __x.imag());
-  const auto [__2i_sin, __2i_cos] = ::cuda::sincos(__2i);
-  _Tp __d(::cuda::std::cosh(__2r) + __2i_cos);
-  _Tp __2rsh(::cuda::std::sinh(__2r));
-  if (::cuda::std::isinf(__2rsh) && ::cuda::std::isinf(__d))
